*reset_floor

@se f=dragstone
@eval exp='o.沼地の廃墟Ｂ１.reset()'
@eval exp='o.沼地の廃墟Ｂ１水中.reset()'
@wait time=800
@warp map=沼地の廃墟Ｂ１ x=6 y=1 way=n
@notice text="All the stones on the floor have returned to their original positions. You were warped back to near the entrance!"

[eventoff]
